 48→void ULFPGameInstance::TransitionToBattle(const FString& BattleLevelName)
 49→{
 50→	if (bIsTransitioning) return;
 51→	bIsTransitioning = true;
 52→
 53→	FString LevelName = BattleLevelName.IsEmpty() ? DefaultBattleLevelName : BattleLevelName;
 54→	UE_LOG(LogTemp, Log, TEXT("切换到战斗关卡: %s"), *LevelName);
 55→
 56→	// 淡出到黑
 57→	UWorld* World = GetWorld();
 58→	if (World)
 59→	{
 60→		APlayerController* PC = World->GetFirstPlayerController();
 61→		if (PC && PC->PlayerCameraManager)
 62→		{
 63→			PC->PlayerCameraManager->StartCameraFade(0.f, 1.f, TransitionFadeDuration, FLinearColor::Black, false, true);
 64→		}
 65→
 66→		// 延迟后加载关卡
 67→		FTimerHandle TimerHandle;
 68→		FString CapturedLevelName = LevelName;
 69→		World->GetTimerManager().SetTimer(TimerHandle, [this, CapturedLevelName]()
 70→		{
 71→			bIsTransitioning = false;
 72→			UGameplayStatics::OpenLevel(this, FName(*CapturedLevelName));
 73→		}, TransitionFadeDuration, false);
 74→	}
 75→	else
 76→	{
 77→		bIsTransitioning = false;
 78→		UGameplayStatics::OpenLevel(this, FName(*LevelName));
 79→	}
 80→}
