16→bool ULFPWorldMapPlayerState::MoveToNode(int32 TargetNodeID, ALFPWorldMapManager* Manager)
17→{
18→	if (!Manager) return false;
19→
20→	// 验证边存在
21→	ALFPWorldMapEdge* Edge = Manager->GetEdge(CurrentNodeID, TargetNodeID);
22→	if (!Edge)
23→	{
24→		UE_LOG(LogTemp, Warning, TEXT("MoveToNode: 节点 %d 和 %d 之间没有边"), CurrentNodeID, TargetNodeID);
25→		return false;
26→	}
27→
28→	// 验证目标节点存在
29→	ALFPWorldMapNode* TargetNode = Manager->GetNode(TargetNodeID);
30→	if (!TargetNode)
31→	{
32→		UE_LOG(LogTemp, Warning, TEXT("MoveToNode: 目标节点 %d 不存在"), TargetNodeID);
33→		return false;
34→	}
35→
36→	// 消耗回合
37→	int32 TurnCost = Edge->TravelTurnCost;
38→	CurrentTurn += TurnCost;
39→
40→	// 更新位置
41→	int32 PrevNodeID = CurrentNodeID;
42→	CurrentNodeID = TargetNodeID;
43→
44→	// 标记为已访问
45→	VisitedNodeIDs.Add(TargetNodeID);
46→
47→	UE_LOG(LogTemp, Log, TEXT("移动: 节点 %d -> %d，消耗 %d 回合（总计 %d）"),
48→		PrevNodeID, TargetNodeID, TurnCost, CurrentTurn);
49→
50→	// 广播
51→	OnTurnChanged.Broadcast(CurrentTurn, TurnPressureThreshold);
52→	OnPlayerNodeChanged.Broadcast(TargetNode);
53→
54→	return true;
55→}
56→
57→TArray<int32> ULFPWorldMapPlayerState::GetReachableNodeIDs(ALFPWorldMapManager* Manager) const
58→{
59→	TArray<int32> Result;
60→	if (!Manager) return Result;
61→
62→	TArray<ALFPWorldMapNode*> Neighbors = Manager->GetNeighbors(CurrentNodeID);
63→	for (ALFPWorldMapNode* Neighbor : Neighbors)
64→	{
65→		if (!Neighbor) continue;
66→
67→		// 检查解锁条件（前置节点必须已访问）
68→		bool bUnlocked = true;
69→		if (!Neighbor->PrerequisiteNodeIDs.IsEmpty())
70→		{
71→			TArray<FString> PrereqIDs;
72→			Neighbor->PrerequisiteNodeIDs.ParseIntoArray(PrereqIDs, TEXT(";"), true);
73→			for (const FString& IDStr : PrereqIDs)
74→			{
75→				int32 PrereqID = FCString::Atoi(*IDStr);
76→				if (!VisitedNodeIDs.Contains(PrereqID))
77→				{
78→					bUnlocked = false;
79→					break;
80→				}
81→			}
82→		}
83→
84→		if (bUnlocked)
85→		{
86→			Result.Add(Neighbor->NodeID);
87→		}
88→	}
89→
90→	return Result;
91→}
